{
  "name": "Lumina AI Studio",
  "description": "A high-end photo editing and generation suite powered by Gemini. Change backgrounds while preserving subjects, apply artistic filters, and generate high-resolution images up to 4K.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  EDIT = 'EDIT',
  GENERATE = 'GENERATE'
}

export enum ImageSize {
  SIZE_1K = '1K',
  SIZE_2K = '2K',
  SIZE_4K = '4K'
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ImageSize } from "../types";

export const editImageWithGemini = async (
  base64Image: string,
  prompt: string,
  mode: 'REPLACE_BACKGROUND' | 'GENERAL_EDIT'
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Specific instruction to preserve the person when replacing background
  const systemPrompt = mode === 'REPLACE_BACKGROUND' 
    ? `You are an expert image editor. Your task is to change the background of this image based on the prompt: "${prompt}". 
       CRITICAL: You MUST NOT change a single thing about the person or main subject in the foreground. 
       Keep their face, body, hair, and clothing exactly as they appear in the original image. 
       Only modify the environment/background behind them.`
    : `Edit this image based on the prompt: "${prompt}". Maintain high quality and realistic results.`;

  const imagePart = {
    inlineData: {
      mimeType: 'image/png',
      data: base64Image.split(',')[1] || base64Image,
    },
  };

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [imagePart, { text: systemPrompt }] },
  });

  if (!response.candidates?.[0]?.content?.parts) {
    throw new Error('No content generated from Gemini');
  }

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error('Failed to extract image from response');
};

export const generateImageWithGemini = async (
  prompt: string,
  size: ImageSize
): Promise<string> => {
  // Ensure we use the latest API key as requested for high-res models
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [
        {
          text: prompt,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: size
      }
    },
  });

  if (!response.candidates?.[0]?.content?.parts) {
    throw new Error('No content generated from Gemini');
  }

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error('Failed to extract image from response');
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { AppMode, ImageSize, GeneratedImage } from './types';
import { editImageWithGemini, generateImageWithGemini } from './services/geminiService';

// Custom window interface for AI Studio helpers
declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export default function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.EDIT);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [imageSize, setImageSize] = useState<ImageSize>(ImageSize.SIZE_1K);
  const [results, setResults] = useState<GeneratedImage[]>([]);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setSelectedImage(readerEvent.target?.result as string);
        setErrorMessage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const checkAndHandleApiKey = async () => {
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
        // Assuming success as per instructions to avoid race conditions
      }
      return true;
    } catch (err) {
      console.error("API Key selection failed", err);
      return false;
    }
  };

  const handleEditAction = async (editType: 'REPLACE_BACKGROUND' | 'GENERAL_EDIT') => {
    if (!selectedImage || !prompt.trim()) return;

    setIsProcessing(true);
    setErrorMessage(null);
    try {
      const result = await editImageWithGemini(selectedImage, prompt, editType);
      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: result,
        prompt: prompt,
        timestamp: Date.now()
      };
      setResults(prev => [newImage, ...prev]);
      setPrompt('');
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes('Requested entity was not found')) {
        setErrorMessage('Session expired or invalid. Please re-select your API key.');
        await window.aistudio.openSelectKey();
      } else {
        setErrorMessage('Failed to process image. Please try again.');
      }
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenerateAction = async () => {
    if (!prompt.trim()) return;

    setIsProcessing(true);
    setErrorMessage(null);
    try {
      await checkAndHandleApiKey();
      const result = await generateImageWithGemini(prompt, imageSize);
      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: result,
        prompt: prompt,
        timestamp: Date.now()
      };
      setResults(prev => [newImage, ...prev]);
      setPrompt('');
    } catch (err: any) {
      console.error(err);
       if (err.message?.includes('Requested entity was not found')) {
        setErrorMessage('Session expired. Re-selecting API key...');
        await window.aistudio.openSelectKey();
      } else {
        setErrorMessage('Failed to generate image. Please check your prompt and key.');
      }
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-950 text-slate-100">
      {/* Header */}
      <header className="px-6 py-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          </div>
          <h1 className="text-xl font-bold tracking-tight">Lumina AI Studio</h1>
        </div>

        <nav className="flex gap-2 p-1 bg-slate-800 rounded-full border border-slate-700">
          <button
            onClick={() => { setMode(AppMode.EDIT); setResults([]); }}
            className={`px-6 py-1.5 rounded-full transition-all text-sm font-medium ${mode === AppMode.EDIT ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-200'}`}
          >
            Studio Edit
          </button>
          <button
            onClick={() => { setMode(AppMode.GENERATE); setResults([]); }}
            className={`px-6 py-1.5 rounded-full transition-all text-sm font-medium ${mode === AppMode.GENERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-200'}`}
          >
            AI Generator
          </button>
        </nav>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Controls */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 shadow-xl space-y-6">
            <h2 className="text-lg font-semibold flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-indigo-500"></span>
              {mode === AppMode.EDIT ? 'Transform Image' : 'Generate New Image'}
            </h2>

            {mode === AppMode.EDIT && (
              <div className="space-y-4">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`relative group h-48 rounded-2xl border-2 border-dashed flex flex-col items-center justify-center transition-all cursor-pointer overflow-hidden
                    ${selectedImage ? 'border-transparent' : 'border-slate-700 hover:border-indigo-500 bg-slate-800/50'}`}
                >
                  {selectedImage ? (
                    <>
                      <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                        <span className="text-sm font-medium">Change Photo</span>
                      </div>
                    </>
                  ) : (
                    <>
                      <div className="p-3 rounded-full bg-slate-700/50 mb-3 text-slate-400 group-hover:text-indigo-400">
                        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                      </div>
                      <p className="text-sm text-slate-400 font-medium">Upload source photo</p>
                    </>
                  )}
                  <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                </div>
              </div>
            )}

            <div className="space-y-3">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">
                Prompt Instruction
              </label>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder={mode === AppMode.EDIT ? "e.g., 'Retro filter' or 'A futuristic neon city background'" : "A high-tech workspace with holographic displays..."}
                className="w-full h-32 bg-slate-800 border border-slate-700 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all resize-none"
              />
            </div>

            {mode === AppMode.GENERATE && (
              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">
                  Resolution
                </label>
                <div className="grid grid-cols-3 gap-2">
                  {[ImageSize.SIZE_1K, ImageSize.SIZE_2K, ImageSize.SIZE_4K].map((size) => (
                    <button
                      key={size}
                      onClick={() => setImageSize(size)}
                      className={`py-2 rounded-xl text-xs font-semibold border transition-all ${imageSize === size ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-400'}`}
                    >
                      {size}
                    </button>
                  ))}
                </div>
                <p className="text-[10px] text-slate-500 italic mt-2">Requires selected API key from a paid project.</p>
              </div>
            )}

            <div className="flex flex-col gap-3">
              {mode === AppMode.EDIT ? (
                <>
                  <button
                    disabled={isProcessing || !selectedImage || !prompt}
                    onClick={() => handleEditAction('REPLACE_BACKGROUND')}
                    className="w-full py-3.5 bg-gradient-to-r from-indigo-600 to-indigo-500 hover:from-indigo-500 hover:to-indigo-400 disabled:opacity-50 disabled:cursor-not-allowed rounded-2xl text-sm font-bold shadow-lg shadow-indigo-500/20 transition-all flex items-center justify-center gap-2"
                  >
                    {isProcessing ? <LoadingIcon /> : null}
                    Change Background
                  </button>
                  <button
                    disabled={isProcessing || !selectedImage || !prompt}
                    onClick={() => handleEditAction('GENERAL_EDIT')}
                    className="w-full py-3.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed rounded-2xl text-sm font-bold transition-all border border-slate-700 flex items-center justify-center gap-2"
                  >
                    {isProcessing ? <LoadingIcon /> : null}
                    Apply Custom Edit
                  </button>
                </>
              ) : (
                <button
                  disabled={isProcessing || !prompt}
                  onClick={handleGenerateAction}
                  className="w-full py-3.5 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed rounded-2xl text-sm font-bold shadow-lg shadow-purple-500/20 transition-all flex items-center justify-center gap-2"
                >
                  {isProcessing ? <LoadingIcon /> : null}
                  Generate Image
                </button>
              )}
            </div>

            {errorMessage && (
              <div className="p-3 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs text-center">
                {errorMessage}
              </div>
            )}
          </div>
        </div>

        {/* Right Column: Results */}
        <div className="lg:col-span-8">
          <div className="bg-slate-900 rounded-3xl min-h-[600px] border border-slate-800 shadow-xl overflow-hidden flex flex-col">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
              <h3 className="font-semibold text-slate-300">Workspace Results</h3>
              <div className="flex gap-2 text-xs text-slate-500">
                <span>{results.length} Image{results.length === 1 ? '' : 's'}</span>
              </div>
            </div>

            <div className="flex-1 p-6 overflow-y-auto">
              {results.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center space-y-4">
                  <div className="w-24 h-24 rounded-full bg-slate-800/30 flex items-center justify-center border border-slate-800/50">
                    <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                  </div>
                  <div className="space-y-1">
                    <p className="font-medium text-slate-400">Ready for your creation</p>
                    <p className="text-sm">Configure your prompt and click generate to see the results here.</p>
                  </div>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {results.map((img) => (
                    <div key={img.id} className="group relative bg-slate-800 rounded-2xl overflow-hidden border border-slate-700 hover:border-indigo-500 transition-all">
                      <img src={img.url} alt={img.prompt} className="w-full aspect-square object-cover" />
                      <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-slate-950/90 to-transparent p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                        <p className="text-xs text-slate-300 line-clamp-2 italic">"{img.prompt}"</p>
                        <div className="flex justify-between items-center mt-2">
                          <span className="text-[10px] text-slate-500">{new Date(img.timestamp).toLocaleTimeString()}</span>
                          <button 
                             onClick={() => {
                               const a = document.createElement('a');
                               a.href = img.url;
                               a.download = `lumina-${img.id}.png`;
                               a.click();
                             }}
                             className="p-1.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white transition-colors"
                          >
                            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                            </svg>
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </main>

      <footer className="p-6 text-center text-slate-600 text-xs border-t border-slate-900">
        <p>&copy; 2024 Lumina AI Studio &bull; Powered by Google Gemini 2.5 & 3.0</p>
      </footer>
    </div>
  );
}

const LoadingIcon = () => (
  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { AppMode, ImageSize, GeneratedImage } from './types';
import { editImageWithGemini, generateImageWithGemini } from './services/geminiService';

// Custom window interface for AI Studio helpers
declare global {
  // Define AIStudio interface to match the existing global type
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    // Use the named AIStudio interface instead of an inline type to resolve property type mismatch and identical modifier requirements.
    aistudio: AIStudio;
  }
}

export default function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.EDIT);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [imageSize, setImageSize] = useState<ImageSize>(ImageSize.SIZE_1K);
  const [results, setResults] = useState<GeneratedImage[]>([]);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setSelectedImage(readerEvent.target?.result as string);
        setErrorMessage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const checkAndHandleApiKey = async () => {
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
        // Assuming success as per instructions to avoid race conditions
      }
      return true;
    } catch (err) {
      console.error("API Key selection failed", err);
      return false;
    }
  };

  const handleEditAction = async (editType: 'REPLACE_BACKGROUND' | 'GENERAL_EDIT') => {
    if (!selectedImage || !prompt.trim()) return;

    setIsProcessing(true);
    setErrorMessage(null);
    try {
      const result = await editImageWithGemini(selectedImage, prompt, editType);
      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: result,
        prompt: prompt,
        timestamp: Date.now()
      };
      setResults(prev => [newImage, ...prev]);
      setPrompt('');
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes('Requested entity was not found')) {
        setErrorMessage('Session expired or invalid. Please re-select your API key.');
        await window.aistudio.openSelectKey();
      } else {
        setErrorMessage('Failed to process image. Please try again.');
      }
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenerateAction = async () => {
    if (!prompt.trim()) return;

    setIsProcessing(true);
    setErrorMessage(null);
    try {
      await checkAndHandleApiKey();
      const result = await generateImageWithGemini(prompt, imageSize);
      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: result,
        prompt: prompt,
        timestamp: Date.now()
      };
      setResults(prev => [newImage, ...prev]);
      setPrompt('');
    } catch (err: any) {
      console.error(err);
       if (err.message?.includes('Requested entity was not found')) {
        setErrorMessage('Session expired. Re-selecting API key...');
        await window.aistudio.openSelectKey();
      } else {
        setErrorMessage('Failed to generate image. Please check your prompt and key.');
      }
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-950 text-slate-100">
      {/* Header */}
      <header className="px-6 py-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          </div>
          <h1 className="text-xl font-bold tracking-tight">Lumina AI Studio</h1>
        </div>

        <nav className="flex gap-2 p-1 bg-slate-800 rounded-full border border-slate-700">
          <button
            onClick={() => { setMode(AppMode.EDIT); setResults([]); }}
            className={`px-6 py-1.5 rounded-full transition-all text-sm font-medium ${mode === AppMode.EDIT ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-200'}`}
          >
            Studio Edit
          </button>
          <button
            onClick={() => { setMode(AppMode.GENERATE); setResults([]); }}
            className={`px-6 py-1.5 rounded-full transition-all text-sm font-medium ${mode === AppMode.GENERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-200'}`}
          >
            AI Generator
          </button>
        </nav>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Controls */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 shadow-xl space-y-6">
            <h2 className="text-lg font-semibold flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-indigo-500"></span>
              {mode === AppMode.EDIT ? 'Transform Image' : 'Generate New Image'}
            </h2>

            {mode === AppMode.EDIT && (
              <div className="space-y-4">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`relative group h-48 rounded-2xl border-2 border-dashed flex flex-col items-center justify-center transition-all cursor-pointer overflow-hidden
                    ${selectedImage ? 'border-transparent' : 'border-slate-700 hover:border-indigo-500 bg-slate-800/50'}`}
                >
                  {selectedImage ? (
                    <>
                      <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                        <span className="text-sm font-medium">Change Photo</span>
                      </div>
                    </>
