import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ImageSize } from "../types";

export const editImageWithGemini = async (
  base64Image: string,
  prompt: string,
  mode: 'REPLACE_BACKGROUND' | 'GENERAL_EDIT',
  templatePromptSuffix?: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const finalPrompt = templatePromptSuffix 
    ? `${prompt}. Style and Background: ${templatePromptSuffix}` 
    : prompt;

  // Specific instruction to preserve the person when replacing background
  const systemPrompt = mode === 'REPLACE_BACKGROUND' 
    ? `You are an expert AI photo compositor. 
       TASK: Replace the background of the provided image.
       THEME: ${finalPrompt}.

       CRITICAL CONSTRAINTS:
       1. DO NOT change the person/subject in the foreground. 
       2. Maintain their exact facial features, hair detail, skin tone, and clothing textures.
       3. The subject must look naturally integrated into the new background (lighting, shadows).
       4. The background should be creative, high-resolution, and visually stunning.`
    : `Edit this image based on the prompt: "${finalPrompt}". Maintain high quality and realistic results.`;

  const imagePart = {
    inlineData: {
      mimeType: 'image/png',
      data: base64Image.split(',')[1] || base64Image,
    },
  };

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [imagePart, { text: systemPrompt }] },
  });

  if (!response.candidates?.[0]?.content?.parts) {
    throw new Error('No content generated from Gemini');
  }

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error('Failed to extract image from response');
};

export const generateImageWithGemini = async (
  prompt: string,
  size: ImageSize
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: size
      }
    },
  });

  if (!response.candidates?.[0]?.content?.parts) {
    throw new Error('No content generated from Gemini');
  }

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error('Failed to extract image from response');
};

