      // Keep prompt if user typed one, clear if it was just a template
      if (!prompt) setActiveTemplate(null);
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes('Requested entity was not found')) {
        await window.aistudio.openSelectKey();
