);

import React, { useState, useRef } from 'react';
import { AppMode, ImageSize, GeneratedImage, BackgroundTemplate } from './types';
import { editImageWithGemini, generateImageWithGemini } from './services/geminiService';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    // Making this optional to match potential pre-existing environment declarations
    aistudio?: AIStudio;
  }
}

const TEMPLATES: BackgroundTemplate[] = [
  { 
    id: 'cyberpunk', 
    name: 'Neo-Tokyo', 
    description: 'Neon-lit futuristic city', 
    thumbnailColor: 'bg-gradient-to-br from-purple-900 to-blue-600',
    promptSuffix: 'A futuristic cyberpunk city at night with neon signs, wet asphalt, and cinematic blue and pink lighting.' 
  },
  { 
    id: 'ethereal', 
    name: 'Mystic Grove', 
    description: 'Enchanted glowing forest', 
    thumbnailColor: 'bg-gradient-to-br from-emerald-900 to-teal-500',
    promptSuffix: 'An ethereal enchanted forest with glowing flora, morning mist, and soft god-rays filtering through leaves.' 
  },
  { 
    id: 'studio', 
    name: 'Minimalist', 
    description: 'Clean professional studio', 
    thumbnailColor: 'bg-gradient-to-br from-slate-400 to-slate-200',
    promptSuffix: 'A clean, high-end minimalist professional photo studio with soft-box lighting and a subtle grey gradient background.' 
  },
  { 
    id: 'mars', 
    name: 'Red Planet', 
    description: 'Cinematic Martian surface', 
