  },
];

export default function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.EDIT);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [activeTemplate, setActiveTemplate] = useState<BackgroundTemplate | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [imageSize, setImageSize] = useState<ImageSize>(ImageSize.SIZE_1K);
  const [results, setResults] = useState<GeneratedImage[]>([]);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setSelectedImage(readerEvent.target?.result as string);
        setErrorMessage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAction = async (editType: 'REPLACE_BACKGROUND' | 'GENERAL_EDIT' | 'GENERATE') => {
    if (editType !== 'GENERATE' && !selectedImage) {
      setErrorMessage('Please upload a photo first.');
      return;
    }

    setIsProcessing(true);
    setErrorMessage(null);
    try {
      let resultUrl: string;
      const finalPrompt = prompt || (activeTemplate?.name || 'High quality edit');

      if (editType === 'GENERATE') {
        // As per guidelines, check for API key selection for high-quality image generation models
        if (window.aistudio) {
          const hasKey = await window.aistudio.hasSelectedApiKey();
          if (!hasKey) {
            await window.aistudio.openSelectKey();
            // Proceed immediately after triggering the dialog to avoid race conditions as per instructions
          }
        }
        resultUrl = await generateImageWithGemini(finalPrompt, imageSize);
      } else {
        resultUrl = await editImageWithGemini(
          selectedImage!, 
          finalPrompt, 
          editType, 
          activeTemplate?.promptSuffix
        );
      }

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: resultUrl,
        prompt: finalPrompt,
        timestamp: Date.now(),
        templateId: activeTemplate?.id
      };
      setResults(prev => [newImage, ...prev]);
      // Keep prompt if user typed one, clear if it was just a template
      if (!prompt) setActiveTemplate(null);
    } catch (err: any) {
      console.error(err);
      // Reset key selection state and prompt user again if "Requested entity was not found" error occurs
      if (err.message?.includes('Requested entity was not found') && window.aistudio) {
        await window.aistudio.openSelectKey();
      } else {
        setErrorMessage('Process failed. Ensure your image is clear and try again.');
      }
    } finally {
      setIsProcessing(false);
    }
  };

  return (
