              <h2 className="text-lg font-bold text-white tracking-tight">
                {mode === AppMode.EDIT ? 'Step 1: Upload & Select' : 'Generate Masterpiece'}
              </h2>
              <p className="text-xs text-slate-500">Fast, accurate background replacement.</p>
            </div>

            {mode === AppMode.EDIT && (
              <div 
                onClick={() => fileInputRef.current?.click()}
