                  ${selectedImage ? 'border-transparent shadow-inner' : 'border-slate-700 hover:border-indigo-500 bg-slate-800/30'}`}
              >
                {selectedImage ? (
                  <>
                    <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
