                      <svg className="w-8 h-8 mb-2 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                      </svg>
                      <span className="text-xs font-bold uppercase tracking-widest text-white">Replace Source</span>
                    </div>
                  </>
                ) : (
                  <>
                    <div className="p-4 rounded-2xl bg-indigo-500/10 mb-4 text-indigo-400 group-hover:scale-110 transition-transform">
