              </div>
            )}
          </div>
        </div>

        <div className="lg:col-span-8 flex flex-col space-y-6">
          <div className="bg-slate-900/50 backdrop-blur-md rounded-3xl min-h-[700px] border border-slate-800/50 shadow-2xl flex flex-col overflow-hidden">
            <div className="p-6 border-b border-slate-800/50 flex justify-between items-center bg-slate-900/30">
              <div className="flex items-center gap-3">
                <h3 className="font-bold text-slate-100 uppercase tracking-widest text-xs">Canvas History</h3>
                <span className="px-2 py-0.5 rounded-md bg-slate-800 text-[10px] text-slate-400 font-mono">{results.length} UNITS</span>
              </div>
              <div className="flex items-center gap-4">
                 {isProcessing && (
                   <div className="flex items-center gap-2">
                     <div className="flex gap-1">
                        <div className="w-1 h-1 rounded-full bg-indigo-500 animate-bounce"></div>
                        <div className="w-1 h-1 rounded-full bg-indigo-500 animate-bounce [animation-delay:-0.15s]"></div>
