import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ImageSize } from "../types";

/**
 * Analyzes a video template to extract style, lighting, and musical "vibe"
 */
export const analyzeVideoMood = async (
  videoBase64: string,
  mimeType: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const videoPart = {
    inlineData: {
      data: videoBase64.split(',')[1] || videoBase64,
      mimeType: mimeType,
    },
  };

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-native-audio-preview-09-2025',
    contents: {
      parts: [
        videoPart,
        { text: "Analyze this video template. Describe its visual aesthetic (colors, lighting, environment) and its musical rhythm/mood. Create a concise 30-word prompt for an AI to generate a matching background for a portrait. Focus on how the music's energy translates to visuals." }
      ]
    }
  });

  return response.text || "A cinematic background matching the video style";
};

export const editImageWithGemini = async (
  base64Image: string,
  prompt: string,
  mode: 'REPLACE_BACKGROUND' | 'GENERAL_EDIT',
  templatePromptSuffix?: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const finalPrompt = templatePromptSuffix 
    ? `${prompt}. ${templatePromptSuffix}` 
    : prompt;

  const systemPrompt = mode === 'REPLACE_BACKGROUND' 
    ? `You are an expert AI photo compositor. 
       TASK: Replace the background of the provided image.
       THEME: ${finalPrompt}.

       CRITICAL CONSTRAINTS:
       1. DO NOT change a single pixel of the person/subject in the foreground. 
       2. Maintain their exact facial features, hair detail, skin tone, and clothing textures.
       3. The subject must look naturally integrated into the new background (lighting, shadows, depth of field).
       4. The background must be creative, cinematic, and perfectly match the requested vibe.`
    : `Edit this image: "${finalPrompt}". Maintain subject integrity.`;

  const imagePart = {
    inlineData: {
      mimeType: 'image/png',
      data: base64Image.split(',')[1] || base64Image,
    },
  };

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [imagePart, { text: systemPrompt }] },
  });

  if (!response.candidates?.[0]?.content?.parts) {
    throw new Error('No content generated');
  }

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error('Failed to extract image');
};

export const generateImageWithGemini = async (
  prompt: string,
  size: ImageSize
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: "1:1", imageSize: size } },
  });
  if (!response.candidates?.[0]?.content?.parts) throw new Error('No content generated');
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error('Failed to extract image');
};

