  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [selectedVideo, setSelectedVideo] = useState<{data: string, type: string} | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStatus, setProcessingStatus] = useState('');
  const [prompt, setPrompt] = useState('');
  const [results, setResults] = useState<GeneratedImage[]>([]);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => setSelectedImage(ev.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 25 * 1024 * 1024) {
        setErrorMessage("Video too large. Use a shorter clip under 25MB.");
        return;
      }
      const reader = new FileReader();
      reader.onload = (ev) => setSelectedVideo({
        data: ev.target?.result as string,
        type: file.type
      });
      reader.readAsDataURL(file);
    }
  };

  const handleSyncAction = async () => {
    if (!selectedImage || !selectedVideo) {
      setErrorMessage("Please upload both a source photo and a video template.");
      return;
    }

    setIsProcessing(true);
    setErrorMessage(null);
    try {
      setProcessingStatus('Listening to music rhythm...');
      // Small delay for UX feel
      await new Promise(r => setTimeout(r, 500));

      setProcessingStatus('Analyzing visual aesthetics...');
      const moodPrompt = await analyzeVideoMood(selectedVideo.data, selectedVideo.type);

      setProcessingStatus('Locking subject & generating background...');
      const resultUrl = await editImageWithGemini(
        selectedImage, 
        prompt || "A professionally shot portrait", 
        'REPLACE_BACKGROUND', 
        `Match the background music and visual energy of: ${moodPrompt}`
      );

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: resultUrl,
        prompt: prompt || moodPrompt,
        timestamp: Date.now(),
        analysisMood: moodPrompt
      };
      setResults(prev => [newImage, ...prev]);
    } catch (err: any) {
      console.error(err);
      setErrorMessage("Synchronization failed. Try a video with more distinct music.");
    } finally {
      setIsProcessing(false);
      setProcessingStatus('');
    }
  };

  const downloadImage = (img: GeneratedImage) => {
    const link = document.createElement('a');
    link.href = img.url;
    link.download = `lumina-sync-${img.id}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-950 text-slate-100 selection:bg-indigo-500/30">
      <header className="px-6 py-4 border-b border-slate-800/50 flex justify-between items-center bg-slate-900/40 backdrop-blur-xl sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-tr from-cyan-400 via-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
            </svg>
          </div>
          <h1 className="text-xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400">LUMINA SYNC</h1>
        </div>

        <nav className="flex gap-1 p-1 bg-slate-800/40 rounded-full border border-slate-700/50">
          <button
            onClick={() => setMode(AppMode.SYNC)}
            className={`px-6 py-1.5 rounded-full transition-all text-[10px] font-black uppercase tracking-widest ${mode === AppMode.SYNC ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
          >
            Magic Sync
          </button>
          <button
            onClick={() => setMode(AppMode.GENERATE)}
            className={`px-6 py-1.5 rounded-full transition-all text-[10px] font-black uppercase tracking-widest ${mode === AppMode.GENERATE ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
          >
            Imagine
          </button>
        </nav>

        <div className="hidden lg:flex items-center gap-2 px-3 py-1 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
           <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
           <span className="text-[9px] font-bold text-emerald-500 uppercase tracking-[0.2em]">Gemini 3 Engaged</span>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-900/60 backdrop-blur-md rounded-3xl p-6 border border-slate-800 shadow-2xl space-y-6">
            <div className="space-y-1">
              <h2 className="text-lg font-bold text-white tracking-tight italic">Sync Workspace</h2>
              <p className="text-xs text-slate-500">Your photo, their vibe. Perfectly matched.</p>
            </div>

            <div className="grid grid-cols-1 gap-4">
              <div 
                onClick={() => imageInputRef.current?.click()}
                className={`relative group h-44 rounded-2xl border-2 border-dashed flex flex-col items-center justify-center transition-all cursor-pointer overflow-hidden
                  ${selectedImage ? 'border-indigo-500/50' : 'border-slate-700 hover:border-indigo-500 bg-slate-800/20'}`}
              >
                {selectedImage ? (
                  <img src={selectedImage} alt="Source" className="w-full h-full object-cover" />
                ) : (
                  <div className="text-center space-y-2">
                    <svg className="w-6 h-6 mx-auto text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <p className="text-[10px] font-black uppercase text-slate-500">Target Photo</p>
                  </div>
                )}
                <input ref={imageInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
              </div>

              <div 
                onClick={() => videoInputRef.current?.click()}
                className={`relative group h-44 rounded-2xl border-2 border-dashed flex flex-col items-center justify-center transition-all cursor-pointer overflow-hidden
                  ${selectedVideo ? 'border-cyan-500/50' : 'border-slate-700 hover:border-cyan-500 bg-slate-800/20'}`}
              >
                {selectedVideo ? (
                  <div className="relative w-full h-full bg-slate-950 flex items-center justify-center">
                    <video src={selectedVideo.data} className="w-full h-full object-cover opacity-50 grayscale hover:grayscale-0 transition-all duration-500" muted autoPlay loop />
                    <span className="absolute text-[8px] font-black uppercase bg-white/10 backdrop-blur-md px-3 py-1.5 rounded-full text-white border border-white/20">Template Locked</span>
                  </div>
                ) : (
                  <div className="text-center space-y-2">
                    <svg className="w-6 h-6 mx-auto text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                    <p className="text-[10px] font-black uppercase text-slate-500">Video Mood Ref</p>
                  </div>
                )}
                <input ref={videoInputRef} type="file" className="hidden" accept="video/*" onChange={handleVideoUpload} />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em]">Direction (Optional)</label>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="e.g., Make it darker, add neon, surreal..."
                className="w-full h-20 bg-slate-950 border border-slate-800 rounded-2xl p-4 text-[11px] focus:ring-1 focus:ring-indigo-500 outline-none transition-all resize-none shadow-inner text-slate-300"
              />
            </div>

            <button
              disabled={isProcessing || !selectedImage || !selectedVideo}
              onClick={handleSyncAction}
              className="w-full py-5 bg-gradient-to-r from-indigo-600 via-indigo-500 to-indigo-600 hover:brightness-110 disabled:opacity-20 rounded-3xl text-[11px] font-black uppercase tracking-[0.3em] shadow-2xl shadow-indigo-500/20 transition-all flex flex-col items-center justify-center gap-1 overflow-hidden relative"
            >
              {isProcessing ? (
                <>
                   <LoadingIcon />
                   <span className="mt-2 text-[8px] tracking-widest animate-pulse font-mono">{processingStatus}</span>
                </>
              ) : 'Run Sync Transform'}
            </button>

            {errorMessage && (
              <div className="p-3 rounded-2xl bg-red-500/5 border border-red-500/20 text-red-400 text-[10px] font-bold text-center uppercase tracking-widest italic">
                {errorMessage}
              </div>
            )}
          </div>
        </div>

        <div className="lg:col-span-8 flex flex-col space-y-6">
          <div className="bg-slate-900/40 backdrop-blur-3xl rounded-3xl min-h-[700px] border border-slate-800/40 shadow-2xl flex flex-col overflow-hidden">
            <div className="p-6 border-b border-slate-800/20 flex justify-between items-center bg-slate-950/20">
              <h3 className="font-black text-slate-400 uppercase tracking-[0.4em] text-[10px]">Processing Results</h3>
              <div className="flex gap-4 items-center">
                <span className="text-[10px] font-bold text-slate-600">{results.length} UNITS</span>
              </div>
            </div>

            <div className="flex-1 p-8 overflow-y-auto custom-scrollbar">
              {results.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-700 text-center space-y-8">
                  <div className="w-40 h-40 rounded-full bg-slate-900/50 border border-slate-800/50 flex items-center justify-center relative group">
                    <div className="absolute inset-0 bg-indigo-500/5 blur-3xl rounded-full animate-pulse group-hover:bg-indigo-500/10 transition-all"></div>
                    <svg className="w-12 h-12 text-slate-800 group-hover:text-indigo-900 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                    </svg>
                  </div>
                  <div className="max-w-sm space-y-3">
                    <p className="font-black text-slate-400 uppercase tracking-[0.5em] text-[10px]">Awaiting Signal</p>
                    <p className="text-[11px] text-slate-600 leading-relaxed uppercase tracking-widest opacity-60">Upload photo and template reference to begin the multi-modal synchronization.</p>
                  </div>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  {results.map((img) => (
                    <div key={img.id} className="group relative bg-slate-950 rounded-[2.5rem] overflow-hidden border border-slate-800/50 hover:border-indigo-500/30 transition-all duration-700 shadow-2xl">
                      <img src={img.url} alt="Output" className="w-full aspect-square object-cover transition-all duration-1000 group-hover:scale-110 group-hover:brightness-75" />

                      <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-slate-950/20 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-500 flex flex-col justify-end p-8">
                        <div className="space-y-5 translate-y-8 group-hover:translate-y-0 transition-transform duration-700 ease-out">
                          <div className="bg-white/5 backdrop-blur-xl p-5 rounded-3xl border border-white/10 space-y-3">
                             <div className="flex gap-2">
                               <span className="text-[8px] font-black uppercase px-2 py-1 rounded-lg bg-indigo-600 text-white tracking-widest">Synced</span>
                               <span className="text-[8px] font-black uppercase px-2 py-1 rounded-lg bg-white/10 text-slate-300 tracking-widest">4K HD</span>
                             </div>
                             <p className="text-[10px] text-white/70 font-bold italic line-clamp-3 leading-relaxed tracking-tight">
                               {img.analysisMood || img.prompt}
                             </p>
                          </div>

                          <div className="flex gap-3">
                            <button 
                               onClick={() => downloadImage(img)}
                               className="flex-1 py-4 rounded-2xl bg-white text-slate-950 text-[10px] font-black uppercase tracking-[0.2em] hover:bg-cyan-400 transition-all active:scale-95 flex items-center justify-center gap-2"
                            >
                              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                              Export PNG
                            </button>
                            <button 
                              onClick={() => setSelectedImage(img.url)}
                              className="p-4 rounded-2xl bg-slate-900/80 text-white hover:bg-slate-800 transition-all border border-white/5 shadow-lg active:scale-90"
                              title="Set as new source"
                            >
                              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                            </button>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </main>

      <footer className="p-8 border-t border-slate-900 flex flex-col items-center gap-4 bg-slate-950 relative overflow-hidden">
        <div className="flex gap-12 text-[8px] font-black uppercase tracking-[0.6em] text-slate-800">
          <span>Sonic Analysis</span>
          <span>Subject preservation</span>
          <span>Aesthetic sync</span>
        </div>
        <p className="text-slate-700 text-[9px] font-bold uppercase tracking-widest opacity-40">
          Powered by Gemini 3 Flash Multimodal Core
        </p>
      </footer>
    </div>
  );
}

const LoadingIcon = () => (
  <svg className="animate-spin h-7 w-7 text-indigo-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-10" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-90" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { getUnifiedChatResponse, fileToBase64 } from '../services/geminiService';
import { Send, User, Sparkles, Loader2, Image as ImageIcon, X, ExternalLink, Target, AlertTriangle, Crosshair, Plus, Clock, Globe } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

interface ChatProps {
  onSignalDetected?: () => void;
}

const ChatInterface: React.FC<ChatProps> = ({ onSignalDetected }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'assistant',
      content: 'Hello! I am **Nova**, your Time, Price, and News synchronized analyst.\n\nI now cross-reference your charts with the **Real-Time Economic Calendar**. When you upload a pair, I will check for upcoming high-impact news (NFP, CPI, Rates) to ensure your "Sniper" entries aren\'t caught in fundamental volatility.\n\nReady for a full-spectrum ICT analysis?',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImages, setSelectedImages] = useState<File[]>([]);
  const [imagePreviews, setImagePreviews] = useState<string[]>([]);
  const [showSniperPulse, setShowSniperPulse] = useState(false);

  const [apiHistory, setApiHistory] = useState<any[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const SYSTEM_INSTRUCTION = `You are Nova, an elite Forex analyst specializing in the ICT (Inner Circle Trader) 'Power of Three': Time, Price, and News.

  CONFLUENCE RULES:
  1. TIME: Identify the current session (London Open 2-5am EST, NY Open 7-10am EST, etc.).
  2. PRICE: Analyze market structure (MSS/BOS), liquidity sweeps, and PD Arrays (FVG, Orderblocks).
  3. NEWS: Use Google Search to find high-impact news for the detected pair. Avoid recommending entries right before red-folder news unless it's a 'News-Fade' setup.

  CRITICAL:
  - If you use Google Search, your response MUST explicitly mention the news you found and how it affects the setup.
  - Maintain long-term multimodal memory of previous charts.
  - Use Markdown. Highlight 'Sniper' entries with 🎯.`;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files: File[] = Array.from(e.target.files || []);
    if (files.length > 0) {
      setSelectedImages(prev => [...prev, ...files]);
      const newPreviews = files.map(file => URL.createObjectURL(file));
      setImagePreviews(prev => [...prev, ...newPreviews]);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeImage = (index: number) => {
    const updatedImages = [...selectedImages];
    const updatedPreviews = [...imagePreviews];
    URL.revokeObjectURL(updatedPreviews[index]);
    updatedImages.splice(index, 1);
    updatedPreviews.splice(index, 1);
    setSelectedImages(updatedImages);
    setImagePreviews(updatedPreviews);
  };

  const handleSend = async () => {
    if ((!input.trim() && selectedImages.length === 0) || isLoading) return;

    const now = new Date();
    const timeContext = `[TIME CONTEXT: Local: ${now.toLocaleTimeString()}, UTC: ${now.toUTCString()}, Timezone: ${Intl.DateTimeFormat().resolvedOptions().timeZone}]. Always convert to EST for ICT Killzone analysis.`;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input || (selectedImages.length > 0 ? `Analyze ${selectedImages.length} chart(s).` : ""),
      timestamp: now,
      type: selectedImages.length > 0 ? 'image' : 'text'
    };
    setMessages(prev => [...prev, userMsg]);

    const parts: any[] = [];
    if (selectedImages.length > 0) {
      for (const file of selectedImages) {
        const b64 = await fileToBase64(file);
        parts.push({ inlineData: { data: b64, mimeType: file.type } });
      }
    }

    const promptWithTime = input.trim() 
      ? `${timeContext} ${input}. Check for high-impact news for any pairs identified.` 
      : `${timeContext} Analyze these charts for ICT setups. Actively search for the economic calendar and news news related to the pair(s) in the images.`;

    parts.push({ text: promptWithTime });

    const updatedHistory = [...apiHistory, { role: 'user', parts }];

    setInput('');
    setSelectedImages([]);
    setImagePreviews([]);
    setIsLoading(true);

    try {
      const result = await getUnifiedChatResponse(updatedHistory, SYSTEM_INSTRUCTION);

      if (result.isSniper) {
        setShowSniperPulse(true);
        setTimeout(() => setShowSniperPulse(false), 2000);
        if (onSignalDetected) onSignalDetected();
      }

      const assistantMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: result.text,
        timestamp: new Date(),
        isSniperSignal: result.isSniper,
        groundingUrls: result.groundingUrls
      };
      setMessages(prev => [...prev, assistantMsg]);
      setApiHistory([...updatedHistory, { role: 'model', parts: [{ text: result.text }] }]);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: "Memory buffer error. I couldn't sync the news data. Please retry.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-950 relative overflow-hidden">
      {showSniperPulse && (
        <div className="absolute inset-0 pointer-events-none z-50 animate-pulse border-4 border-indigo-500/50 bg-indigo-500/5 transition-opacity duration-1000"></div>
      )}

      <div className="flex-1 overflow-y-auto p-4 space-y-6 no-scrollbar" ref={scrollRef}>
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[92%] flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${m.role === 'user' ? 'bg-indigo-900/50' : 'bg-slate-800'}`}>
                {m.role === 'user' ? <User size={16} className="text-indigo-400" /> : <Sparkles size={16} className="text-indigo-400" />}
              </div>
              <div className={`p-4 rounded-2xl shadow-lg border relative ${m.role === 'user' ? 'bg-indigo-600 border-indigo-500 text-white rounded-tr-none' : m.isSniperSignal ? 'bg-slate-900 border-indigo-500/50 text-slate-200 rounded-tl-none ring-1 ring-indigo-500/20 shadow-[0_0_20px_rgba(99,102,241,0.1)]' : 'bg-slate-900 border-slate-800 text-slate-200 rounded-tl-none'}`}>

                {m.isSniperSignal && (
                  <div className="flex items-center gap-1.5 bg-indigo-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full absolute -top-2 left-2 animate-bounce uppercase tracking-widest shadow-lg">
                    <Target size={10} /> Sniper Identified
                  </div>
                )}

                <div className={`prose prose-sm max-w-none ${m.role === 'user' ? 'prose-invert text-white' : 'prose-invert text-slate-200'}`}>
                  <ReactMarkdown remarkPlugins={[remarkGfm]}>{m.content}</ReactMarkdown>
                </div>

                {m.groundingUrls && m.groundingUrls.length > 0 && (
                  <div className="mt-4 pt-3 border-t border-slate-800 flex flex-col gap-1.5">
                    <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-1">
                      <Globe size={10}/> Fundamental Sources
                    </span>
                    <div className="flex flex-wrap gap-2">
                      {m.groundingUrls.map((url, i) => (
                        <a 
                          key={i} 
                          href={url.uri} 
                          target="_blank" 
                          className="bg-slate-950 text-[9px] font-bold text-indigo-400 px-2.5 py-1 rounded-lg border border-slate-800 flex items-center gap-1.5 hover:border-indigo-500/50 transition-colors"
                        >
                          {url.title || 'Source'} <ExternalLink size={8} />
                        </a>
                      ))}
                    </div>
                  </div>
                )}

                <span className={`text-[9px] mt-2 block font-bold uppercase tracking-widest ${m.role === 'user' ? 'text-indigo-200/60' : 'text-slate-500'} flex items-center gap-1`}>
