    if (estHour >= 2 && estHour < 5) return { name: 'London Killzone', color: 'text-amber-400' };
    if (estHour >= 7 && estHour < 10) return { name: 'NY Open Killzone', color: 'text-emerald-400' };
    if (estHour >= 10 && estHour < 12) return { name: 'London Close', color: 'text-rose-400' };
    if (estHour >= 20 || estHour < 0) return { name: 'Asian Session', color: 'text-indigo-400' };
    return { name: 'Off-Session (Dead Time)', color: 'text-slate-500' };
  };

