    switch (activeModule) {
      case 'forex':
        return (
          <div className="space-y-6 animate-in slide-in-from-right-4">
            <div className="bg-amber-600 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-110 transition-transform duration-1000"><Globe size={120}/></div>
               <div className="relative z-10">
                 <p className="text-amber-100 text-[10px] font-black uppercase tracking-[0.2em] opacity-80 flex items-center gap-2">
                   <Clock size={12}/> <MarketClock />
                 </p>
                 <h2 className="text-4xl font-black mt-2 tracking-tighter">Forex Markets</h2>

                 <div className="mt-4 p-4 bg-black/20 rounded-2xl backdrop-blur-md border border-white/10">
                    <p className="text-[8px] font-black text-amber-200 uppercase tracking-widest mb-1">Active Killzone</p>
                    <p className={`text-sm font-black uppercase tracking-wider ${session.color}`}>{session.name}</p>
                 </div>
               </div>

               <div className="flex gap-4 mt-6">
                 <button onClick={loadForexIntel} className="flex items-center gap-1.5 bg-white/10 px-4 py-2 rounded-2xl text-[10px] font-black backdrop-blur-md border border-white/5 uppercase">
                   {isLoadingForex ? <RefreshCcw size={14} className="animate-spin" /> : <RefreshCcw size={14} />} Sync Intelligence
                 </button>
               </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h3 className="font-bold text-slate-100 flex items-center gap-2"><AlertCircle size={18} className="text-red-400"/> High-Impact News</h3>
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Global Pulse</span>
              </div>

              {isLoadingForex ? (
                <div className="flex flex-col items-center justify-center py-20 gap-4 bg-slate-900 rounded-3xl border border-slate-800">
                  <Loader2 className="animate-spin text-amber-500" size={32} />
