                </div>
              ) : (
                <div className="space-y-4">
                  {forexAlerts.length > 0 ? (
                    forexAlerts.map(alert => (
                      <div key={alert.id} className="bg-slate-900 rounded-3xl p-6 border-l-4 border-red-500 border-y border-r border-slate-800 shadow-xl group hover:border-red-500/50 transition-all">
                        <div className="flex justify-between items-start mb-4">
                          <div>
                            <span className="bg-red-500/10 text-red-500 text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest border border-red-500/20">Impact Analysis</span>
                            <h4 className="text-lg font-black text-slate-100 mt-2">{alert.event}</h4>
                          </div>
                          <span className="text-[10px] font-bold text-slate-500">{alert.timestamp}</span>
                        </div>

                        <div className="flex flex-wrap gap-2 mb-4">
                          {alert.assets.map(asset => (
                            <span key={asset} className="bg-slate-950 text-slate-400 text-[9px] font-black px-3 py-1 rounded-xl border border-slate-800">
                              {asset}
                            </span>
                          ))}
