                        <div className="bg-slate-950 rounded-2xl p-4 border border-slate-800 space-y-3">
                          <div className="flex items-center justify-between">
                            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Nova Prediction</span>
                            <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded-lg ${alert.signal.toLowerCase().includes('buy') ? 'bg-emerald-500/10 text-emerald-400' : alert.signal.toLowerCase().includes('sell') ? 'bg-red-500/10 text-red-400' : 'bg-slate-800 text-slate-400'}`}>
                              {alert.signal}
                            </span>
                          </div>
                          <p className="text-xs text-slate-300 leading-relaxed font-medium">
                            <span className="text-indigo-400 font-bold">Time Context:</span> {alert.logic}
