          <div className="mt-12 flex gap-2">
            {[1,2,3,4,5].map(i => <div key={i} className="w-1.5 h-10 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: `${i*0.1}s`}}></div>)}
          </div>
