    if (utcHour >= 7 && utcHour < 16) {
      // London Killzone: 07:00 - 10:00 UTC
      if (utcHour < 10) return { name: 'London Killzone', color: 'text-amber-400', active: true };
      return { name: 'London Session', color: 'text-amber-400/60', active: true };
