                  </div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] animate-pulse">Syncing Red Folder Events...</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {forexAlerts.length > 0 ? (
