              <div className="flex gap-4 overflow-x-auto pb-4 no-scrollbar -mx-4 px-4">
                {wallets.map(w => (
                  <div key={w.id} className="min-w-[160px] bg-slate-900 p-5 rounded-3xl border border-slate-800 shadow-sm">
