export const getUnifiedChatResponse = async (history: any[], systemInstruction: string) => {
  const ai = getAI();

  const response = await ai.models.generateContent({
    model: MODELS.COMPLEX,
    contents: history,
    config: {
      systemInstruction: systemInstruction + ` 
      USER CONTEXT: LiteFinance Demo Competition ($5,000 Starting Balance).
      GOAL: Top 5 Ranking in 1 month.
      MANDATE: Recommend AGGRESSIVE yet calculated lot sizes (e.g., 0.5 to 1.0 lots per $5k for high-conviction sweeps). 
      Identify exact 'Sniper' entry points at 15m Fair Value Gaps after a 1h Liquidity Sweep.`,
      thinkingConfig: { thinkingBudget: 4000 },
      tools: [{ googleSearch: {} }] 
    }
  });

  const text = response.text || "";
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const urls = chunks.map((c: any) => c.web).filter(Boolean).map((w: any) => ({ uri: w.uri, title: w.title }));

  const isSniper = (text.toLowerCase().includes("sniper") || text.includes("🎯")) && 
                   (text.toLowerCase().includes("purge") || text.toLowerCase().includes("sweep") || text.toLowerCase().includes("raid"));

  return {
    text,
    isSniper,
    groundingUrls: urls
  };
};

