import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { getUnifiedChatResponse, fileToBase64 } from '../services/geminiService';
import { Send, User, Sparkles, Loader2, Image as ImageIcon, X, ExternalLink, Target, AlertTriangle, Crosshair, Plus, Clock, Globe, ShieldCheck, Trophy, TrendingUp, Zap } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

interface ChatProps {
  onSignalDetected?: () => void;
}

const ChatInterface: React.FC<ChatProps> = ({ onSignalDetected }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'assistant',
      content: '🚀 **LiteFinance Demo Mode Engaged!**\n\nStarting Capital: **$5,000**.\nTarget: **Top 5 Global Ranking**.\n\nI have adjusted my risk-to-reward parameters for high-intensity competition. I will now suggest **Aggressive Lot Sizes** (0.5 - 1.0 Lots) on high-conviction sniper setups to push us up the leaderboard fast.\n\nUpload your chart or pair name—let’s find the sweep and displace the competition.',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImages, setSelectedImages] = useState<File[]>([]);
  const [imagePreviews, setImagePreviews] = useState<string[]>([]);
  const [showSniperPulse, setShowSniperPulse] = useState(false);

  const [apiHistory, setApiHistory] = useState<any[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const SYSTEM_INSTRUCTION = `You are Nova, an elite Institutional Forex Analyst. 

  COMPETITION CONTEXT: LiteFinance $5,000 Demo. 
  OBJECTIVE: High Growth for Top 5 Ranking.

  CORE STRATEGY: 
  - Identify LIQUIDITY PURGES on 1H/4H timeframes.
  - Call SNIPER ENTRIES on 5m/15m displacements.
  - RISK MANAGEMENT: For this competition, suggest lots between 0.2 and 1.0 depending on the setup quality.
  - NEVER trade against the daily bias.

  RESPONSE FORMAT:
  - **PAIR & BIAS**: [e.g., EURUSD - BULLISH]
  - **SNIPER ZONE**: [Price level of Fair Value Gap]
  - **LOT SIZE**: [Competitive recommendation for $5k balance]
  - **RANKING TIP**: [Strategic advice to beat other traders]`;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleFocus = () => {
    setTimeout(() => {
      inputRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 300);
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files: File[] = Array.from(e.target.files || []);
    if (files.length > 0) {
      setSelectedImages(prev => [...prev, ...files]);
      const newPreviews = files.map(file => URL.createObjectURL(file));
      setImagePreviews(prev => [...prev, ...newPreviews]);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeImage = (index: number) => {
    const updatedImages = [...selectedImages];
    const updatedPreviews = [...imagePreviews];
    URL.revokeObjectURL(updatedPreviews[index]);
    updatedImages.splice(index, 1);
    updatedPreviews.splice(index, 1);
    setSelectedImages(updatedImages);
    setImagePreviews(updatedPreviews);
  };

  const handleSend = async () => {
    if ((!input.trim() && selectedImages.length === 0) || isLoading) return;

    const now = new Date();
    const timeContext = `[DEMO COMPETITION MODE] [BALANCE: $5,000] [TIME: ${now.toLocaleTimeString()}]. Pair analysis requested. Focus on Top 5 ranking strategy.`;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input || (selectedImages.length > 0 ? `Scan for a $5k sniper sweep.` : ""),
      timestamp: now,
      type: selectedImages.length > 0 ? 'image' : 'text'
    };
    setMessages(prev => [...prev, userMsg]);

    const parts: any[] = [];
    if (selectedImages.length > 0) {
      for (const file of selectedImages) {
        const b64 = await fileToBase64(file);
        parts.push({ inlineData: { data: b64, mimeType: file.type } });
      }
    }

    parts.push({ text: `${timeContext} ${input}` });

    const updatedHistory = [...apiHistory, { role: 'user', parts }];

    setInput('');
    setSelectedImages([]);
    setImagePreviews([]);
    setIsLoading(true);

    try {
      const result = await getUnifiedChatResponse(updatedHistory, SYSTEM_INSTRUCTION);

      if (result.isSniper) {
        setShowSniperPulse(true);
        setTimeout(() => setShowSniperPulse(false), 2000);
        if (onSignalDetected) onSignalDetected();
      }

      const assistantMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: result.text,
        timestamp: new Date(),
        isSniperSignal: result.isSniper,
        groundingUrls: result.groundingUrls
      };
      setMessages(prev => [...prev, assistantMsg]);
      setApiHistory([...updatedHistory, { role: 'model', parts: [{ text: result.text }] }]);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: "Competitive Analysis Engine error. High server load from competition participants.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-950 relative overflow-hidden">
      <div className="bg-indigo-600/10 border-b border-indigo-500/20 p-3 flex items-center justify-between z-20">
        <div className="flex items-center gap-2">
          <Trophy className="text-amber-400" size={16} />
          <span className="text-[10px] font-black text-slate-100 uppercase tracking-widest">LiteFinance Competition Mode</span>
        </div>
        <div className="flex items-center gap-2 bg-indigo-500/20 px-2 py-1 rounded-lg">
          <Zap size={12} className="text-amber-400" />
          <span className="text-[10px] font-black text-indigo-300">$5,000 Demo</span>
        </div>
      </div>

      {showSniperPulse && (
        <div className="absolute inset-0 pointer-events-none z-50 animate-pulse border-4 border-indigo-500/50 bg-indigo-500/5 transition-opacity duration-1000"></div>
      )}

      <div className="flex-1 overflow-y-auto p-4 space-y-6 no-scrollbar" ref={scrollRef}>
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[92%] flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${m.role === 'user' ? 'bg-indigo-900/50' : 'bg-slate-800'}`}>
                {m.role === 'user' ? <User size={16} className="text-indigo-400" /> : <Sparkles size={16} className="text-indigo-400" />}
              </div>
              <div className={`p-4 rounded-2xl shadow-lg border relative ${m.role === 'user' ? 'bg-indigo-600 border-indigo-500 text-white rounded-tr-none' : m.isSniperSignal ? 'bg-slate-900 border-indigo-500/50 text-slate-200 rounded-tl-none ring-1 ring-indigo-500/20 shadow-[0_0_20px_rgba(99,102,241,0.1)]' : 'bg-slate-900 border-slate-800 text-slate-200 rounded-tl-none'}`}>

                {m.isSniperSignal && (
                  <div className="flex items-center gap-1.5 bg-indigo-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full absolute -top-2 left-2 animate-bounce uppercase tracking-widest shadow-lg">
                    <ShieldCheck size={10} /> Sniper Entry Confirmed
                  </div>
                )}

                <div className={`prose prose-sm max-w-none ${m.role === 'user' ? 'prose-invert text-white' : 'prose-invert text-slate-200'}`}>
                  <ReactMarkdown remarkPlugins={[remarkGfm]}>{m.content}</ReactMarkdown>
                </div>

                {m.groundingUrls && m.groundingUrls.length > 0 && (
                  <div className="mt-4 pt-3 border-t border-slate-800 flex flex-col gap-1.5">
                    <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-1">
                      <Globe size={10}/> Global Intel
                    </span>
                    <div className="flex flex-wrap gap-2">
                      {m.groundingUrls.map((url, i) => (
                        <a 
                          key={i} 
                          href={url.uri} 
                          target="_blank" 
                          className="bg-slate-950 text-[9px] font-bold text-indigo-400 px-2.5 py-1 rounded-lg border border-slate-800 flex items-center gap-1.5"
                        >
                          {url.title || 'Source'} <ExternalLink size={8} />
                        </a>
                      ))}
                    </div>
                  </div>
                )}

                <span className={`text-[9px] mt-2 block font-bold uppercase tracking-widest ${m.role === 'user' ? 'text-indigo-200/60' : 'text-slate-500'} flex items-center gap-1`}>
                  <Clock size={10}/> {m.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-900 p-3 px-5 rounded-2xl border border-slate-800 flex items-center gap-3">
              <TrendingUp className="animate-pulse text-indigo-500" size={16} />
              <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Analyzing for Top 5 Win...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-950 border-t border-slate-900/50 sticky bottom-0 space-y-3 z-10">
        {imagePreviews.length > 0 && (
          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
            {imagePreviews.map((preview, index) => (
              <div key={index} className="relative flex-shrink-0 group">
                <img src={preview} alt={`Chart ${index + 1}`} className="h-20 w-20 object-cover rounded-xl border-2 border-indigo-500 shadow-xl" />
                <button 
                  onClick={() => removeImage(index)} 
                  className="absolute -top-2 -right-2 bg-rose-500 text-white p-1 rounded-full shadow-lg"
                >
                  <X size={10} />
                </button>
              </div>
            ))}
            <button onClick={() => fileInputRef.current?.click()} className="h-20 w-20 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-xl bg-slate-900/50 text-slate-500 hover:border-indigo-500">
              <Plus size={20} />
              <span className="text-[8px] font-black uppercase mt-1">Add Chart</span>
            </button>
          </div>
        )}

        <div className="flex gap-2">
          {imagePreviews.length === 0 && (
            <button onClick={() => fileInputRef.current?.click()} className="bg-slate-900 text-slate-400 p-4 rounded-2xl border border-slate-800">
              <ImageIcon size={20} />
            </button>
          )}
          <input type="file" ref={fileInputRef} onChange={handleImageSelect} accept="image/*" multiple className="hidden" />
          <input
            ref={inputRef}
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            onFocus={handleFocus}
            placeholder="Pair Name? Top 5 Strategy?"
            autoComplete="off"
            className="flex-1 p-4 bg-slate-900 border border-slate-800 rounded-2xl outline-none text-slate-100 text-sm shadow-inner"
          />
          <button
            onClick={handleSend}
            disabled={(!input.trim() && selectedImages.length === 0) || isLoading}
            className="bg-indigo-600 text-white p-4 rounded-2xl shadow-xl shadow-indigo-600/20 active:scale-95 transition-all"
