  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'assistant',
      content: '🎯 **High-Conviction Sniper Protocol Activated.**\n\nI have updated my logic to prevent "Stop Loss Fatigue". I will now ONLY call a signal after verifying:\n1. **SMT Divergence** (Correlation Check).\n2. **ICT Displacement** (Impulsive FVG).\n3. **Red Folder News** (Real-time Audit).\n4. **Liquidity Sweeps** (Retail Stop Purges).\n\nIf the setup is low-quality, I will stay flat. We want WINS to reach the Top 5. Send your chart.',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImages, setSelectedImages] = useState<File[]>([]);
  const [imagePreviews, setImagePreviews] = useState<string[]>([]);
  const [showSniperPulse, setShowSniperPulse] = useState(false);

  const [apiHistory, setApiHistory] = useState<any[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const SYSTEM_INSTRUCTION = `You are Nova, an elite Institutional Strategist. 

  MANDATE: WIN-RATE IS PRIORITY.

  ELITE CHECKLIST BEFORE SIGNAL:
  - **SMT**: Check correlation (DXY vs Gold, EUR vs GBP).
  - **NEWS**: Use Search to verify red folder events.
  - **DISPLACEMENT**: Must see a strong BOS/MSS.
  - **CANDLES**: Confirm with 15m structural shift.

  If the chart shows "Retail Support" or "Vague Momentum", advise the user to STAY FLAT. 

  RESPONSE FORMAT:
  - **MARKET CONDITION**: [Live Sync]
  - **ELITE CHECKLIST**: [SMT/News/Sweep status]
  - **VERDICT**: [BUY/SELL/STAY FLAT]
  - **ENTRY & TARGETS**: [If Verdict is not Flat]
  - **RISK TO $2,500 FLOOR**: [Distance calculation]`;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleFocus = () => {
    setTimeout(() => {
      inputRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 300);
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files: File[] = Array.from(e.target.files || []);
    if (files.length > 0) {
      setSelectedImages(prev => [...prev, ...files]);
      const newPreviews = files.map(file => URL.createObjectURL(file));
      setImagePreviews(prev => [...prev, ...newPreviews]);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeImage = (index: number) => {
    const updatedImages = [...selectedImages];
    const updatedPreviews = [...imagePreviews];
    URL.revokeObjectURL(updatedPreviews[index]);
    updatedImages.splice(index, 1);
    updatedPreviews.splice(index, 1);
    setSelectedImages(updatedImages);
    setImagePreviews(updatedPreviews);
  };

  const handleSend = async () => {
    if ((!input.trim() && selectedImages.length === 0) || isLoading) return;

    const now = new Date();
    const timeContext = `[DEMO COMPETITION] [STOP-OUT: $2,500] [BALANCE: $5,000]. MANDATORY: Perform SMT, News, and Displacement checks before signal. Protect win rate.`;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input || (selectedImages.length > 0 ? `Verify this setup for High Conviction entry.` : ""),
      timestamp: now,
      type: selectedImages.length > 0 ? 'image' : 'text'
    };
    setMessages(prev => [...prev, userMsg]);

    const parts: any[] = [];
    if (selectedImages.length > 0) {
      for (const file of selectedImages) {
        const b64 = await fileToBase64(file);
        parts.push({ inlineData: { data: b64, mimeType: file.type } });
      }
    }

    parts.push({ text: `${timeContext} ${input}` });

    const updatedHistory = [...apiHistory, { role: 'user', parts }];

    setInput('');
    setSelectedImages([]);
    setImagePreviews([]);
    setIsLoading(true);

    try {
      const result = await getUnifiedChatResponse(updatedHistory, SYSTEM_INSTRUCTION);

      if (result.isSniper) {
        setShowSniperPulse(true);
        setTimeout(() => setShowSniperPulse(false), 2000);
        if (onSignalDetected) onSignalDetected();
      }

      const assistantMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: result.text,
        timestamp: new Date(),
        isSniperSignal: result.isSniper,
        groundingUrls: result.groundingUrls
      };
      setMessages(prev => [...prev, assistantMsg]);
      setApiHistory([...updatedHistory, { role: 'model', parts: [{ text: result.text }] }]);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: "Intel Engine calibration error. Please stay flat until servers stabilize.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-950 relative overflow-hidden">
      <div className="bg-indigo-600/10 border-b border-indigo-500/20 p-3 flex items-center justify-between z-20">
        <div className="flex items-center gap-2">
          <ShieldCheck className="text-emerald-400" size={16} />
          <span className="text-[10px] font-black text-slate-100 uppercase tracking-widest">High-Conviction Audit Mode</span>
        </div>
        <div className="flex items-center gap-2 bg-rose-500/20 px-2 py-1 rounded-lg">
          <AlertTriangle size={12} className="text-rose-400" />
          <span className="text-[10px] font-black text-rose-300">Target Win Rate: 90%+</span>
        </div>
      </div>

      {showSniperPulse && (
        <div className="absolute inset-0 pointer-events-none z-50 animate-pulse border-4 border-indigo-500/50 bg-indigo-500/5 transition-opacity duration-1000"></div>
      )}

      <div className="flex-1 overflow-y-auto p-4 space-y-6 no-scrollbar" ref={scrollRef}>
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[92%] flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${m.role === 'user' ? 'bg-indigo-900/50' : 'bg-slate-800'}`}>
                {m.role === 'user' ? <User size={16} className="text-indigo-400" /> : <Sparkles size={16} className="text-indigo-400" />}
              </div>
              <div className={`p-4 rounded-2xl shadow-lg border relative ${m.role === 'user' ? 'bg-indigo-600 border-indigo-500 text-white rounded-tr-none' : m.isSniperSignal ? 'bg-slate-900 border-emerald-500/40 text-slate-200 rounded-tl-none ring-1 ring-emerald-500/20 shadow-[0_0_30px_rgba(16,185,129,0.05)]' : 'bg-slate-900 border-slate-800 text-slate-200 rounded-tl-none'}`}>

