              <div key={index} className="relative flex-shrink-0 group">
                <img src={preview} alt={`Chart ${index + 1}`} className="h-20 w-20 object-cover rounded-xl border-2 border-indigo-500 shadow-xl" />
                <button 
                  onClick={() => removeImage(index)} 
